/// <summary>
/// extension of table <c>AssetBook</c>
/// </summary>
[ExtensionOf(tableStr(AssetBook))]

internal final class ETGAssetBook_Extension
{

}

Method.Source:
/// <summary>
/// used from date (Placed in Service date) is not earlier than the acquisition date,
/// </summary>
/// <returns>boolean</returns>
public boolean validateWrite()
{
    boolean ret = next validateWrite(); 

    if (ret && ETGACFParameters::find().EnableUATSmallPoints && (this.UsedFromDate < this.AcquisitionDate))
    {
        ret = checkFailed(strFmt("@ETG_New:AcquisitionDateComparison", this.UsedFromDate, this.AcquisitionDate));
    }

    return ret;
}
